SELECT o.*, cp.customer_name, cp.phone, cp.allergy_tags,
       pp.package_name as parent_package_name,
       sp.sub_package_name as child_package_name
FROM customer_order o
LEFT JOIN customer_profile cp ON o.customer_id = cp.id
LEFT JOIN parent_package pp ON o.parent_package_id = pp.id
LEFT JOIN sub_package sp ON o.child_package_id = sp.id


        AND o.order_code LIKE CONCAT('%', #{criteria.orderCode}, '%')


        AND o.customer_id = #{criteria.customerId}


        AND o.customer_code = #{criteria.customerCode}


        AND cp.customer_name LIKE CONCAT('%', #{criteria.customerName}, '%')


        AND o.status = #{criteria.status}


        AND o.customer_source = #{criteria.customerSource}


        AND o.deal_time >= #{criteria.dealTime[0]}
        AND o.deal_time <= #{criteria.dealTime[1]}


        AND o.start_date >= #{criteria.startDate[0]}
        AND o.start_date <= #{criteria.startDate[1]}


        AND o.end_date >= #{criteria.endDate[0]}
        AND o.end_date <= #{criteria.endDate[1]}


ORDER BY o.id DESC

